     .article-copyright-info-container {
    font-family: 'Geist Variable', -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Microsoft YaHei', 'Heiti SC', 'WenQuanYi Micro Hei', sans-serif;
    position: relative;
    width: 100%;
    box-sizing: border-box;
    padding: 10px 6px;
    font-size: 1rem;
    font-family: "EagleLake",cursive;
    background: #531212;
    border-radius: 14px;
    border: 1px solid var(--shadow-color-1);
    }
    .wl-btn.primary {
    border-color: var(--waline-theme-color);
    background: #881144;
    color: #ffffff;
}
.page-container .main-content-container .main-content-body {
    box-sizing: border-box;
    width: 100%;
    display: flex;
    justify-content: center;
    padding: 38px 0;
    background-image: url("https://www.helloimg.com/i/2026/06/16/6a30d5f015d0d.png")
}

@font-face{
    font-family: 'EagleLake';
    src: url('../../../../../fonts/EagleLake.ttf');   
}

.navbar-container .navbar-content .logo-title {
    font-size: 1.4rem;
    font-family: "EagleLake",cursive;
    font-weight: 520;
    line-height: 1;
    color: #881144;
    transform: translateY(1px);
}
a {
    color: #881144;
    text-decoration: inherit;
}

.text-third-text-color {
    color: #881144;
}

.font-semibold {
    font-weight: 600;
    font-family: "EagleLake",cursive;
    color: #e01e72ff;
}

.article-meta-info {
    font-size: 0.8rem;
    color: #881144;
}

.post-toc-wrap .post-toc .toc-title {
    font-size: 0.8rem;
    color: #881144;
    font-weight: 500;
    margin-bottom: 0.2rem;
}

.post-toc-wrap .post-toc .page-title {
    white-space: normal;
    font-size: 1.1rem;
    color: #881144;
    font-weight: bold;
    margin-bottom: 0.6rem;
}
